import type { FC } from 'react';
import React from 'react';

import { AnimatedProgress } from './AnimatedProgress';
import { CircleProgress } from './CircleProgress';
import { LinearProgress } from './LinearProgress';
import type { ProgressProps } from './Progress.types';

export const Progress: FC<ProgressProps> = ({
	value = 0,
	shape = 'linear',
	cycled = false,
	strokeWidth = 4,
	size = 44,
	type = 'container',
	...props
}) => {
	if (shape === 'linear') {
		return <LinearProgress value={value} type={type} cycled={cycled} strokeWidth={strokeWidth} {...props} />;
	}
	if (shape === 'animated') {
		return <AnimatedProgress {...props} />;
	}

	// В случае передачи 0 в круговой прогресс.
	if (!size) {
		return;
	}

	return <CircleProgress value={value} cycled={cycled} strokeWidth={strokeWidth} size={size} {...props} />;
};
